import { useEffect, useMemo, useRef, useState } from "react";
import { Link } from "react-router-dom";

import { api } from "../../lib/api";
import { useAppBootstrap } from "../../hooks/useAppBootstrap";
import { useAppStore } from "../../state/store";
import type { JobSummary } from "../../types/api";
import { JobCreateForm } from "./JobCreateForm";

function StatusBadge({ status }: { status: JobSummary["status"] }) {
  const colors: Record<JobSummary["status"], string> = {
    queued: "bg-stone-200 text-stone-700",
    rendering: "bg-amber-200 text-amber-800",
    paused: "bg-slate-200 text-slate-700",
    playing: "bg-emerald-200 text-emerald-800",
    completed: "bg-teal-200 text-teal-800",
    failed: "bg-rose-200 text-rose-800",
  };

  return <span className={`rounded-full px-3 py-1 text-xs font-semibold ${colors[status]}`}>{status}</span>;
}

export function JobsPage() {
  const jobs = useAppStore((state) => state.jobs);
  const setJobs = useAppStore((state) => state.setJobs);
  const websocketStatus = useAppStore((state) => state.websocketStatus);
  const [error, setError] = useState<string | null>(null);
  const hasLocalMutationRef = useRef(false);
  const hasLiveJobs = useMemo(
    () => jobs.some((job) => job.status !== "completed" && job.status !== "failed"),
    [jobs],
  );

  useAppBootstrap(hasLiveJobs);

  useEffect(() => {
    let cancelled = false;
    void api
      .listJobs()
      .then((nextJobs) => {
        if (!cancelled && !hasLocalMutationRef.current) {
          setJobs(nextJobs);
        }
      })
      .catch((loadError) => {
        if (!cancelled) {
          setError(loadError instanceof Error ? loadError.message : "Unable to load jobs");
        }
      });

    return () => {
      cancelled = true;
    };
  }, [setJobs]);

  const handleCreateJob = async (formData: FormData) => {
    setError(null);
    try {
      const response = await api.createJob(formData);
      hasLocalMutationRef.current = true;
      const currentJobs = useAppStore.getState().jobs;
      setJobs([response.job, ...currentJobs.filter((job) => job.id !== response.job.id)]);
    } catch (createError) {
      setError(createError instanceof Error ? createError.message : "Unable to create job");
    }
  };

  return (
    <div className="grid gap-6 lg:grid-cols-[1.2fr_1fr]">
      <div className="space-y-4">
        <div>
          <p className="text-sm uppercase tracking-[0.3em] text-stone-600">Queue</p>
          <h1 className="display-font text-5xl">ReadFlow jobs</h1>
          <p className="mt-2 max-w-2xl text-stone-700">
            Build a queue, let the scheduler keep buffers healthy, and jump into any reader when you
            are ready to listen.
          </p>
        </div>
        {error ? <div className="rounded-2xl bg-rose-100 px-4 py-3 text-rose-800">{error}</div> : null}
        <div className="panel rounded-[2rem] p-6">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-semibold">Live jobs</h2>
            <span className="text-sm text-stone-600">
              WebSocket: {hasLiveJobs ? websocketStatus : "idle"}
            </span>
          </div>
          <div className="space-y-3">
            {jobs.length === 0 ? (
              <div className="rounded-2xl border border-dashed border-stone-300 px-4 py-8 text-center text-stone-600">
                No jobs yet.
              </div>
            ) : (
              jobs.map((job) => (
                <Link
                  className="block rounded-3xl border border-stone-200 bg-white/70 px-5 py-4 transition hover:-translate-y-0.5"
                  key={job.id}
                  to={`/jobs/${job.id}`}
                >
                  <div className="flex items-center justify-between gap-4">
                    <div>
                      <div className="font-semibold">{job.title ?? "Untitled job"}</div>
                      <div className="text-sm text-stone-600">
                        {job.total_chunks_completed}/{job.total_chunks_emitted} chunks ready
                      </div>
                    </div>
                    <StatusBadge status={job.status} />
                  </div>
                </Link>
              ))
            )}
          </div>
        </div>
      </div>
      <JobCreateForm onSubmit={handleCreateJob} />
    </div>
  );
}

import { FormEvent, useState } from "react";

interface JobCreateFormProps {
  onSubmit: (formData: FormData) => Promise<void>;
}

export function JobCreateForm({ onSubmit }: JobCreateFormProps) {
  const [text, setText] = useState("");
  const [title, setTitle] = useState("");
  const [file, setFile] = useState<File | null>(null);
  const [submitting, setSubmitting] = useState(false);

  const handleSubmit = async (event: FormEvent) => {
    event.preventDefault();
    const formData = new FormData();
    if (title) {
      formData.append("title", title);
    }
    if (text.trim()) {
      formData.append("text", text.trim());
    }
    if (file) {
      formData.append("file", file);
    }
    setSubmitting(true);
    try {
      await onSubmit(formData);
      setText("");
      setTitle("");
      setFile(null);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form className="panel rounded-[2rem] p-6" onSubmit={handleSubmit}>
      <div className="flex flex-col gap-4">
        <div>
          <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="job-title">
            Job title
          </label>
          <input
            className="w-full rounded-2xl border border-stone-300 bg-white/70 px-4 py-3"
            id="job-title"
            value={title}
            onChange={(event) => setTitle(event.target.value)}
            placeholder="Optional title"
          />
        </div>
        <div>
          <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="job-text">
            Text source
          </label>
          <textarea
            className="min-h-56 w-full rounded-3xl border border-stone-300 bg-white/70 px-4 py-3"
            id="job-text"
            value={text}
            onChange={(event) => setText(event.target.value)}
            placeholder="Paste long-form text here"
          />
        </div>
        <label className="rounded-2xl border border-dashed border-stone-400 bg-white/40 px-4 py-4 text-sm">
          <span className="font-semibold">Upload .txt instead</span>
          <input
            className="mt-2 block"
            type="file"
            accept=".txt"
            onChange={(event) => setFile(event.target.files?.[0] ?? null)}
          />
        </label>
        <button
          className="rounded-full bg-[var(--accent)] px-5 py-3 font-semibold text-white disabled:opacity-50"
          disabled={submitting || (!text.trim() && !file)}
          type="submit"
        >
          {submitting ? "Creating…" : "Create job"}
        </button>
      </div>
    </form>
  );
}

export type JobStatus = "queued" | "rendering" | "paused" | "playing" | "completed" | "failed";
export type ChunkStatus = "planned" | "queued" | "rendering" | "written" | "stale" | "failed";
export type WebSocketStatus = "connecting" | "open" | "reconnecting" | "closed" | "error";

export interface Chunk {
  index: number;
  status: ChunkStatus;
  duration_seconds: number;
  start_seconds: number;
  plan_version: number;
  voice_id: string;
  segment_url: string | null;
}

export interface JobSummary {
  id: string;
  title: string | null;
  status: JobStatus;
  voice_id: string;
  model_id: string;
  is_active_listening: boolean;
  total_chunks_emitted: number;
  total_chunks_completed: number;
  buffered_seconds: number;
  completed_seconds: number;
}

export interface JobDetail extends JobSummary {
  source_kind: string;
  source_text: string;
  plan_version: number;
  chunks: Chunk[];
  failed_reason: string | null;
}

export interface JobManifest {
  mime_type: string;
  init_segment_url: string | null;
  chunks: Chunk[];
}

export interface Voice {
  id: string;
  display_name: string;
  description: string | null;
}

export interface AdminConfig {
  idle_unload_seconds: number;
  max_prebuffer_seconds: number;
  target_buffer_seconds: number;
  batch_candidates_small_model: number[];
  batch_candidates_large_model: number[];
  vram_soft_limit_mb: number;
  vram_hard_limit_mb: number;
}

export interface SchedulerState {
  queue_depth: number;
  batch_candidates: number[];
}

export interface AdminState {
  config: AdminConfig;
  scheduler: SchedulerState;
  telemetry: {
    queue_depth: number;
    model_state: string;
    idle_deadline: number | null;
    oom_count: number;
    recent_batches: Array<{
      batch_size: number;
      duration_seconds: number;
      reserved_vram_mb: number;
      allocated_vram_mb: number;
      at: number;
    }>;
    recent_events: Array<{
      type: string;
      payload: Record<string, unknown>;
      at: number;
    }>;
  };
}

export interface WsEnvelope {
  type:
    | "job_created"
    | "job_updated"
    | "job_completed"
    | "chunk_ready"
    | "scheduler_state"
    | "model_state"
    | "telemetry"
    | "admin_config_updated"
    | "pong";
  payload: Record<string, unknown>;
}

import type {
  AdminConfig,
  AdminState,
  JobDetail,
  JobManifest,
  JobSummary,
  Voice,
} from "../types/api";
import { apiPath } from "./transport";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const response = await fetch(path, {
    headers: {
      ...(init?.body instanceof FormData ? {} : { "Content-Type": "application/json" }),
      ...init?.headers,
    },
    ...init,
  });
  if (!response.ok) {
    throw new Error(`Request failed: ${response.status}`);
  }
  if (response.status === 204) {
    return undefined as T;
  }
  return (await response.json()) as T;
}

function parseDownloadFilename(contentDisposition: string | null, fallback: string) {
  if (!contentDisposition) {
    return fallback;
  }
  const utf8Match = contentDisposition.match(/filename\*=UTF-8''([^;]+)/i);
  if (utf8Match?.[1]) {
    return decodeURIComponent(utf8Match[1]);
  }
  const quotedMatch = contentDisposition.match(/filename="([^"]+)"/i);
  if (quotedMatch?.[1]) {
    return quotedMatch[1];
  }
  return fallback;
}

export const api = {
  listJobs: () => request<JobSummary[]>(apiPath("/jobs")),
  getJob: (jobId: string) => request<JobDetail>(apiPath(`/jobs/${jobId}`)),
  createJob: (formData: FormData) =>
    request<{ job: JobDetail }>(apiPath("/jobs"), { method: "POST", body: formData }),
  getManifest: (jobId: string) => request<JobManifest>(apiPath(`/jobs/${jobId}/manifest`)),
  activateJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/activate`), { method: "POST" }),
  pauseJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/pause`), { method: "POST" }),
  resumeJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/resume`), { method: "POST" }),
  updateJobVoice: (jobId: string, voiceId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/voice`), {
      method: "POST",
      body: JSON.stringify({ voice_id: voiceId }),
    }),
  updatePlayback: (jobId: string, currentTimeSeconds: number, isPlaying: boolean) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/playback`), {
      method: "POST",
      body: JSON.stringify({
        current_time_seconds: currentTimeSeconds,
        is_playing: isPlaying,
      }),
    }),
  downloadJobAudio: async (jobId: string) => {
    const response = await fetch(apiPath(`/jobs/${jobId}/download`));
    if (!response.ok) {
      let detail = `Request failed: ${response.status}`;
      try {
        const payload = (await response.json()) as { detail?: string };
        if (payload.detail) {
          detail = payload.detail;
        }
      } catch {
        // Ignore non-JSON error bodies and keep the status-based fallback.
      }
      throw new Error(detail);
    }
    return {
      blob: await response.blob(),
      filename: parseDownloadFilename(
        response.headers.get("content-disposition"),
        `readflow-job-${jobId}.m4a`,
      ),
    };
  },
  listVoices: () => request<Voice[]>(apiPath("/voices")),
  getAdminState: () => request<AdminState>(apiPath("/admin/state")),
  updateAdminConfig: (config: Partial<AdminConfig>) =>
    request<AdminConfig>(apiPath("/admin/config"), {
      method: "POST",
      body: JSON.stringify(config),
    }),
  warmModel: () => request<{ status: string }>(apiPath("/admin/model/warm"), { method: "POST" }),
  evictModel: () =>
    request<{ status: string }>(apiPath("/admin/model/evict"), { method: "POST" }),
};

from __future__ import annotations

import json
from dataclasses import dataclass
from pathlib import Path

from app.core.config import Settings


@dataclass(slots=True)
class VoicePrompt:
    voice_id: str
    reference_text: str
    reference_audio_path: str


@dataclass(slots=True)
class VoiceDefinition:
    id: str
    display_name: str
    description: str | None
    ref_audio_path: str
    ref_text_path: str


class VoiceRegistry:
    def __init__(self, settings: Settings, base_dir: Path) -> None:
        self._voices_dir = base_dir / settings.voices_dir
        self._voices: dict[str, VoiceDefinition] = {}
        self._prompt_cache: dict[str, VoicePrompt] = {}
        self._load_voices()

    def list_voices(self) -> list[VoiceDefinition]:
        return sorted(self._voices.values(), key=lambda item: item.display_name.lower())

    def get_voice(self, voice_id: str) -> VoiceDefinition:
        try:
            return self._voices[voice_id]
        except KeyError as exc:
            raise KeyError(f"Unknown voice '{voice_id}'") from exc

    def get_prompt(self, voice_id: str) -> VoicePrompt:
        if voice_id in self._prompt_cache:
            return self._prompt_cache[voice_id]
        voice = self.get_voice(voice_id)
        prompt = VoicePrompt(
            voice_id=voice.id,
            reference_text=Path(voice.ref_text_path).read_text(encoding="utf-8").strip(),
            reference_audio_path=voice.ref_audio_path,
        )
        self._prompt_cache[voice_id] = prompt
        return prompt

    def _load_voices(self) -> None:
        if not self._voices_dir.exists():
            raise RuntimeError(
                f"Voice directory '{self._voices_dir}' does not exist. "
                "Provide built-in voices under server/voices/<voice_id>/."
            )
        for voice_dir in sorted(self._voices_dir.iterdir()):
            if not voice_dir.is_dir():
                continue
            meta_path = voice_dir / "meta.json"
            ref_audio_path = voice_dir / "ref.wav"
            ref_text_path = voice_dir / "ref.txt"
            missing = [
                str(path.name)
                for path in (meta_path, ref_audio_path, ref_text_path)
                if not path.exists()
            ]
            if missing:
                raise RuntimeError(
                    f"Voice '{voice_dir.name}' is missing required files: {', '.join(missing)}"
                )
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
            reference_text = ref_text_path.read_text(encoding="utf-8").strip()
            if not reference_text:
                raise RuntimeError(f"Voice '{voice_dir.name}' has an empty ref.txt")
            voice = VoiceDefinition(
                id=voice_dir.name,
                display_name=meta.get("display_name", voice_dir.name.replace("_", " ").title()),
                description=meta.get("description"),
                ref_audio_path=str(ref_audio_path),
                ref_text_path=str(ref_text_path),
            )
            self._voices[voice.id] = voice
        if not self._voices:
            raise RuntimeError(
                f"No built-in voices were discovered in '{self._voices_dir}'. "
                "Add real voice folders before starting the app."
            )

from __future__ import annotations

import json
import re
from collections.abc import Callable

from fastapi import APIRouter, Depends, File, Form, HTTPException, UploadFile, WebSocket
from fastapi.responses import FileResponse
from starlette.background import BackgroundTask
from starlette.websockets import WebSocketDisconnect

from app.core.services import AppServices
from app.jobs.models import ChunkStatus, Job, JobStatus
from app.schemas.api import (
    AdminConfigResponse,
    AdminConfigUpdateRequest,
    AdminStateResponse,
    CreateJobResponse,
    JobDetailResponse,
    JobManifestResponse,
    JobSummaryResponse,
    PlaybackUpdateRequest,
    SchedulerStateResponse,
    UpdateVoiceRequest,
    VoiceResponse,
    WsEnvelope,
    chunk_to_response,
    job_to_detail,
    job_to_summary,
)


def build_router(get_services: Callable[[], AppServices]) -> APIRouter:
    router = APIRouter(prefix="/api")

    async def services() -> AppServices:
        return get_services()

    def admin_config_response(app_services: AppServices) -> AdminConfigResponse:
        runtime = app_services.settings.runtime
        return AdminConfigResponse(
            idle_unload_seconds=runtime.idle_unload_seconds,
            max_prebuffer_seconds=runtime.max_prebuffer_seconds,
            target_buffer_seconds=runtime.target_buffer_seconds,
            batch_candidates_small_model=runtime.batch_candidates_small_model,
            batch_candidates_large_model=runtime.batch_candidates_large_model,
            vram_soft_limit_mb=runtime.vram_soft_limit_mb,
            vram_hard_limit_mb=runtime.vram_hard_limit_mb,
        )

    def contiguous_export_wav_paths(job: Job) -> list[str]:
        wav_paths: list[str] = []
        for expected_index, chunk in enumerate(sorted(job.chunks, key=lambda item: item.index)):
            if chunk.index != expected_index:
                break
            if chunk.status != ChunkStatus.WRITTEN or not chunk.wav_path:
                break
            wav_paths.append(chunk.wav_path)
        return wav_paths

    def sanitize_download_name(value: str | None) -> str:
        raw = (value or "readflow-job").strip().lower()
        sanitized = re.sub(r"[^a-z0-9]+", "-", raw).strip("-")
        return sanitized[:80] or "readflow-job"

    @router.get("/jobs", response_model=list[JobSummaryResponse])
    async def list_jobs(app_services: AppServices = Depends(services)) -> list[JobSummaryResponse]:
        return [job_to_summary(job) for job in app_services.job_manager.list_jobs()]

    @router.post("/jobs", response_model=CreateJobResponse)
    async def create_job(
        text: str | None = Form(default=None),
        title: str | None = Form(default=None),
        voice_id: str | None = Form(default=None),
        language: str | None = Form(default=None),
        file: UploadFile | None = File(default=None),
        app_services: AppServices = Depends(services),
    ) -> CreateJobResponse:
        if file is None and not text:
            raise HTTPException(status_code=400, detail="Provide text or a .txt upload")
        payload_text = text or ""
        source_kind = "text"
        if file is not None:
            if not file.filename or not file.filename.endswith(".txt"):
                raise HTTPException(status_code=400, detail="Only .txt uploads are supported")
            payload_text = (await file.read()).decode("utf-8")
            source_kind = "txt_file"
        voice = voice_id or app_services.settings.runtime.default_voice_id
        try:
            app_services.voice_registry.get_voice(voice)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc
        job = app_services.job_manager.create_job(
            source_text=payload_text,
            source_kind=source_kind,
            model_id=app_services.settings.runtime.default_model_id,
            voice_id=voice,
            language=language or app_services.settings.runtime.default_language,
            title=title,
        )
        detail = job_to_detail(job)
        envelope = WsEnvelope(type="job_created", payload={"job": detail.model_dump()})
        app_services.telemetry.record_event("job_created", {"job_id": job.id})
        await app_services.hub.broadcast(envelope.model_dump())
        return CreateJobResponse(job=detail)

    @router.get("/jobs/{job_id}", response_model=JobDetailResponse)
    async def get_job(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> JobDetailResponse:
        try:
            return job_to_detail(app_services.job_manager.get_job(job_id))
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc

    @router.get("/jobs/{job_id}/manifest", response_model=JobManifestResponse)
    async def get_manifest(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> JobManifestResponse:
        try:
            job = app_services.job_manager.get_job(job_id)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc
        init_path = app_services.media_store.init_segment_path(job_id)
        return JobManifestResponse(
            mime_type=app_services.settings.chunk_mime_type,
            init_segment_url=f"/api/jobs/{job_id}/chunks/init" if init_path.exists() else None,
            chunks=[
                chunk_to_response(job, chunk)
                for chunk in sorted(job.chunks, key=lambda item: item.index)
            ],
        )

    @router.get("/jobs/{job_id}/chunks/init")
    async def get_init_segment(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> FileResponse:
        path = app_services.media_store.init_segment_path(job_id)
        if not path.exists():
            raise HTTPException(status_code=404, detail="Init segment not ready")
        return FileResponse(path, media_type=app_services.settings.chunk_mime_type)

    @router.get("/jobs/{job_id}/chunks/{chunk_index}")
    async def get_chunk(
        job_id: str, chunk_index: int, app_services: AppServices = Depends(services)
    ) -> FileResponse:
        path = app_services.media_store.segment_path(job_id, chunk_index)
        if not path.exists():
            raise HTTPException(status_code=404, detail="Chunk not ready")
        return FileResponse(path, media_type=app_services.settings.chunk_mime_type)

    @router.get("/jobs/{job_id}/download")
    async def download_job_audio(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> FileResponse:
        try:
            job = app_services.job_manager.get_job(job_id)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc

        wav_paths = contiguous_export_wav_paths(job)
        if not wav_paths:
            raise HTTPException(status_code=409, detail="No contiguous rendered audio is ready")

        export_path = app_services.media_store.build_export_file(job_id, wav_paths)
        is_full_export = job.status == JobStatus.COMPLETED and len(wav_paths) == len(job.chunks)
        filename = sanitize_download_name(job.title)
        if not is_full_export:
            filename = f"{filename}-partial"

        return FileResponse(
            export_path,
            media_type="audio/mp4",
            filename=f"{filename}.m4a",
            background=BackgroundTask(export_path.unlink, missing_ok=True),
        )

    @router.post("/jobs/{job_id}/activate", response_model=JobDetailResponse)
    async def activate_job(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> JobDetailResponse:
        try:
            job = app_services.job_manager.activate_job(job_id)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc
        detail = job_to_detail(job)
        await app_services.hub.broadcast(
            WsEnvelope(type="job_updated", payload={"job": detail.model_dump()}).model_dump()
        )
        return detail

    @router.post("/jobs/{job_id}/pause", response_model=JobDetailResponse)
    async def pause_job(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> JobDetailResponse:
        try:
            job = app_services.job_manager.pause_job(job_id)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc
        detail = job_to_detail(job)
        await app_services.hub.broadcast(
            WsEnvelope(type="job_updated", payload={"job": detail.model_dump()}).model_dump()
        )
        return detail

    @router.post("/jobs/{job_id}/resume", response_model=JobDetailResponse)
    async def resume_job(
        job_id: str, app_services: AppServices = Depends(services)
    ) -> JobDetailResponse:
        try:
            job = app_services.job_manager.resume_job(job_id)
        except KeyError as exc:
